async function checkBalance() {
  if (!contract) {
    alert('Please set contract address first');
    return;
  }

  const address = document.getElementById('balanceAddress')?.value || userAddress;

  if (!ethers.utils.isAddress(address)) {
    alert('Invalid address');
    return;
  }

  try {
    showLoading(true);
    const balance = await contract.balanceOf(address);
    const formattedBalance = ethers.utils.formatEther(balance);
    
    displayResult(`Balance of ${address}: ${formattedBalance} tokens`);
    logTransaction('Balance check', { address, balance: formattedBalance });
  } catch (error) {
    console.error('Error checking balance:', error);
    alert('Failed to check balance: ' + error.message);
  } finally {
    showLoading(false);
  }
}

async function executeCustomCall() {
  if (!contract) {
    alert('Please set contract address first');
    return;
  }

  const functionSignature = document.getElementById('customFunction')?.value || '';
  const paramsJson = document.getElementById('customParams')?.value || '[]';
  const isWrite = document.getElementById('customIsWrite')?.checked || false;
  const valueInEth = document.getElementById('customValue')?.value || '0';

  try {
    showLoading(true);
    const params = JSON.parse(paramsJson);
    const processedParams = params.map(param => {
      if (typeof param === 'string' && param.includes('.')) {
        return ethers.utils.parseEther(param);
      }
      return param;
    });

    const txOptions = {};
    if (valueInEth && parseFloat(valueInEth) > 0) {
      txOptions.value = ethers.utils.parseEther(valueInEth);
    }

    if (isWrite) {
      const tx = await contract[functionSignature](...processedParams, txOptions);
      displayResult(`Transaction sent: ${tx.hash}`);
      logTransaction('Custom write call initiated', { 
        function: functionSignature, 
        params: processedParams, 
        hash: tx.hash 
      });

      const receipt = await tx.wait();
      displayResult(`Transaction confirmed in block ${receipt.blockNumber}`);
      logTransaction('Custom write call confirmed', { 
        function: functionSignature, 
        hash: tx.hash, 
        block: receipt.blockNumber 
      });
    } else {
      const result = await contract[functionSignature](...processedParams);
      displayResult(`Result: ${JSON.stringify(result, null, 2)}`);
      logTransaction('Custom read call', { 
        function: functionSignature, 
        params: processedParams, 
        result: result.toString() 
      });
    }
  } catch (error) {
    console.error('Error executing custom call:', error);
    alert('Failed to execute custom call: ' + error.message);
  } finally {
    showLoading(false);
  }
}

async function sendTransaction() {
  const to = document.getElementById('txTo')?.value || '';
  const value = document.getElementById('txValue')?.value || '0';
  const data = document.getElementById('txData')?.value || '0x';

  if (!ethers.utils.isAddress(to)) {
    alert('Invalid recipient address');
    return;
  }

  try {
    showLoading(true);
    const tx = await signer.sendTransaction({
      to: to,
      value: ethers.utils.parseEther(value),
      data: data
    });

    displayResult(`Transaction sent: ${tx.hash}`);
    logTransaction('Raw transaction sent', { to, value, hash: tx.hash });

    const receipt = await tx.wait();
    displayResult(`Transaction confirmed in block ${receipt.blockNumber}`);
    logTransaction('Raw transaction confirmed', { 
      to, 
      value, 
      hash: tx.hash, 
      block: receipt.blockNumber 
    });
  } catch (error) {
    console.error('Error sending transaction:', error);
    alert('Failed to send transaction: ' + error.message);
  } finally {
    showLoading(false);
  }
}

async function estimateGas() {
  if (!contract) {
    alert('Please set contract address first');
    return;
  }

  const functionName = document.getElementById('gasFunction')?.value || 'transfer';
  const params = document.getElementById('gasParams')?.value || '';

  try {
    showLoading(true);
    let gasEstimate;

    if (functionName === 'transfer') {
      const [to, amount] = params.split(',').map(p => p.trim());
      gasEstimate = await contract.estimateGas.transfer(to, ethers.utils.parseEther(amount));
    } else if (functionName === 'approve') {
      const [spender, amount] = params.split(',').map(p => p.trim());
      gasEstimate = await contract.estimateGas.approve(spender, ethers.utils.parseEther(amount));
    } else if (functionName === 'setValue') {
      gasEstimate = await contract.estimateGas.setValue(params);
    }

    displayResult(`Estimated gas: ${gasEstimate.toString()} units`);
    logTransaction('Gas estimation', { function: functionName, gas: gasEstimate.toString() });
  } catch (error) {
    console.error('Error estimating gas:', error);
    alert('Failed to estimate gas: ' + error.message);
  } finally {
    showLoading(false);
  }
}

async function getTransactionReceipt() {
  const txHash = document.getElementById('receiptHash')?.value || '';

  if (!txHash.match(/^0x[a-fA-F0-9]{64}$/)) {
    alert('Invalid transaction hash');
    return;
  }

  try {
    showLoading(true);
    const receipt = await provider.getTransactionReceipt(txHash);
    
    if (!receipt) {
      displayResult('Transaction not found or pending');
      return;
    }

    const receiptInfo = {
      blockNumber: receipt.blockNumber,
      blockHash: receipt.blockHash,
      status: receipt.status === 1 ? 'Success' : 'Failed',
      gasUsed: receipt.gasUsed.toString(),
      from: receipt.from,
      to: receipt.to,
      contractAddress: receipt.contractAddress
    };

    displayResult(`Receipt: ${JSON.stringify(receiptInfo, null, 2)}`);
    logTransaction('Receipt retrieved', { hash: txHash, receipt: receiptInfo });
  } catch (error) {
    console.error('Error getting receipt:', error);
    alert('Failed to get receipt: ' + error.message);
  } finally {
    showLoading(false);
  }
}

async function handleAccountsChanged(accounts) {
  if (accounts.length === 0) {
    alert('Please connect to MetaMask');
  } else {
    await initializeApp();
  }
}

function handleChainChanged() {
  window.location.reload();
}

function displayResult(message) {
  const resultElement = document.getElementById('result');
  if (resultElement) {
    resultElement.textContent = message;
    resultElement.style.display = 'block';
  }
  console.log('Result:', message);
}

function logTransaction(action, details) {
  const logElement = document.getElementById('transactionLog');
  if (logElement) {
    const logEntry = document.createElement('div');
    logEntry.className = 'log-entry';
    logEntry.textContent = `${new Date().toLocaleTimeString()} - ${action}: ${JSON.stringify(details)}`;
    logElement.appendChild(logEntry);
    logElement.scrollTop = logElement.scrollHeight;
  }
  console.log(`${action}:`, details);
}

function showLoading(show) {
  const loader = document.getElementById('loader');
  if (loader) {
    loader.style.display = show ? 'block' : 'none';
  }
}

async function getNetworkInfo() {
  try {
    const network = await provider.getNetwork();
    const blockNumber = await provider.getBlockNumber();
    const gasPrice = await provider.getGasPrice();
    
    const networkInfo = {
      chainId: network.chainId,
      name: network.name,
      blockNumber: blockNumber,
      gasPrice: ethers.utils.formatUnits(gasPrice, 'gwei') + ' gwei'
    };

    displayResult(`Network: ${JSON.stringify(networkInfo, null, 2)}`);
    logTransaction('Network info', networkInfo);
  } catch (error) {
    console.error('Error getting network info:', error);
    alert('Failed to get network info: ' + error.message);
  }
}

async function signMessage() {
  const message = document.getElementById('messageToSign')?.value || '';

  if (!message) {
    alert('Please enter a message to sign');
    return;
  }

  try {
    showLoading(true);
    const signature = await signer.signMessage(message);
    displayResult(`Signature: ${signature}`);
    logTransaction('Message signed', { message, signature });
  } catch (error) {
    console.error('Error signing message:', error);
    alert('Failed to sign message: ' + error.message);
  } finally {
    showLoading(false);
  }
}

if (typeof window !== 'undefined' && window.ethereum) {
  window.addEventListener('load', () => {
    setupEventListeners();
  });
}

const DAppAPI = {
  initialize: initializeApp,
  setContract: setContractAddress,
  read: readContractData,
  write: writeContractData,
  transfer: transferTokens,
  approve: approveTokens,
  checkBalance: checkBalance,
  customCall: executeCustomCall,
  sendTx: sendTransaction,
  estimateGas: estimateGas,
  getReceipt: getTransactionReceipt,
  getNetwork: getNetworkInfo,
  signMessage: signMessage,
  getProvider: () => provider,
  getSigner: () => signer,
  getContract: () => contract,
  getUserAddress: () => userAddress
};

if (typeof module !== 'undefined' && module.exports) {
  module.exports = DAppAPI;
}